import React from 'react';

const CertificationItems = ({ item }) => {
  const hasLink =
    typeof item.link === 'string' &&
    /^https?:\/\//i.test(item.link.trim());

  return (
    <div className="certification_card">
      {item.image && (
        <img
          src={item.image}
          alt={item.title}
          className="certification_img"
        />
      )}

      <h3 className="certification_title">{item.title}</h3>

      {item.topic && (
        <span className="certification_topic">{item.topic}</span>
      )}

      {item.tags && item.tags.length > 0 && (
        <div className="certification_tags">
          {item.tags.map((tag) => (
            <span className="certification_tag" key={tag}>
              {tag}
            </span>
          ))}
        </div>
      )}

      {hasLink ? (
        <a
          href={item.link}
          className="certification_button"
          target="_blank"
          rel="noopener noreferrer"
          aria-label={`Open ${item.title} certificate`}
        >
          View Certificate
          <i className="bx bx-right-arrow-alt certification_button-icon"></i>
        </a>
      ) : (
        <span className="certification_button certification_button--ghost">
          Local Certificate
          <i className="bx bx-image certification_button-icon"></i>
        </span>
      )}
    </div>
  );
};

export default CertificationItems;
